#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>

#define SESSION_TIMEOUT 300 // 5 minutes
#define CACHE_SIZE 100

typedef struct {
    char session_id[50];
    char *data;
    time_t last_accessed;
} Session;

typedef struct {
    Session sessions[CACHE_SIZE];
    int count;
} SessionCache;

SessionCache cache = { .count = 0 };

void init_session(Session *session, const char *session_id) {
    strcpy(session->session_id, session_id);
    session->data = (char *)malloc(1024); // 1KB for user data
    session->last_accessed = time(NULL);
}

Session *find_session(const char *session_id) {
    for (int i = 0; i < cache.count; ++i) {
        if (strcmp(cache.sessions[i].session_id, session_id) == 0) {
            return &cache.sessions[i];
        }
    }
    return NULL;
}

void create_session(const char *session_id) {
    if (cache.count < CACHE_SIZE) {
        init_session(&cache.sessions[cache.count++], session_id);
    } else {
        printf("Session Cache Full\n");
    }
}

void access_session(const char *session_id) {
    Session *session = find_session(session_id);
    if (session) {
        session->last_accessed = time(NULL);
        printf("Session %s accessed\n", session_id);
    } else {
        printf("Session %s not found\n", session_id);
    }
}

void invalidate_sessions() {
    time_t now = time(NULL);
    for (int i = 0; i < cache.count; ++i) {
        if (difftime(now, cache.sessions[i].last_accessed) > SESSION_TIMEOUT) {
            free(cache.sessions[i].data);
            cache.sessions[i].data = NULL;
        }
    }
}

void print_sessions() {
    for (int i = 0; i < cache.count; ++i) {
        printf("Session ID: %s, Last Accessed: %ld, Expired: %s\n",
               cache.sessions[i].session_id,
               cache.sessions[i].last_accessed,
               cache.sessions[i].data == NULL ? "Yes" : "No");
    }
}

